import{c as o,Q as l,j as i,m as t}from"./chunks/framework.5k1Nei9d.js";const q=JSON.parse('{"title":"刷机常见问题 FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/faq.md","filePath":"tutorials/faq.md"}'),r={name:"tutorials/faq.md"};function e(s,a,n,h,d,c){return l(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="刷机常见问题-faq" tabindex="-1">刷机常见问题 FAQ <a class="header-anchor" href="#刷机常见问题-faq" aria-label="Permalink to &quot;刷机常见问题 FAQ&quot;">​</a></h1><h2 id="刷机相关" tabindex="-1">刷机相关 <a class="header-anchor" href="#刷机相关" aria-label="Permalink to &quot;刷机相关&quot;">​</a></h2><h3 id="q-刷机后卡在开机动画-bootloop-怎么办" tabindex="-1">Q: 刷机后卡在开机动画（Bootloop）怎么办？ <a class="header-anchor" href="#q-刷机后卡在开机动画-bootloop-怎么办" aria-label="Permalink to &quot;Q: 刷机后卡在开机动画（Bootloop）怎么办？&quot;">​</a></h3><ol><li>强制关机：长按电源键 10-15 秒</li><li>进入 Recovery 模式</li><li>清除 Cache/Dalvik Cache</li><li>如果仍然无法开机，恢复之前的备份或重刷 ROM</li></ol><h3 id="q-手机变砖还能救吗" tabindex="-1">Q: 手机变砖还能救吗？ <a class="header-anchor" href="#q-手机变砖还能救吗" aria-label="Permalink to &quot;Q: 手机变砖还能救吗？&quot;">​</a></h3><p><strong>软砖</strong>（能进 Fastboot/Recovery）：</p><ul><li>通过 Fastboot 刷入官方固件</li><li>或在 Recovery 中恢复备份</li></ul><p><strong>硬砖</strong>（完全无法开机）：</p><ul><li>可能需要售后或专业维修</li><li><strong>建议操作前充分了解风险</strong></li></ul><h3 id="q-刷机需要备份哪些数据" tabindex="-1">Q: 刷机需要备份哪些数据？ <a class="header-anchor" href="#q-刷机需要备份哪些数据" aria-label="Permalink to &quot;Q: 刷机需要备份哪些数据？&quot;">​</a></h3><ul><li>联系人、短信、通话记录</li><li>照片、视频、文档</li><li>应用数据（微信聊天记录等）</li><li><strong>完整 Nandroid 备份</strong>（Recovery → Backup）</li></ul><h2 id="root-相关" tabindex="-1">Root 相关 <a class="header-anchor" href="#root-相关" aria-label="Permalink to &quot;Root 相关&quot;">​</a></h2><h3 id="q-root-后银行-app-打不开怎么办" tabindex="-1">Q: Root 后银行 App 打不开怎么办？ <a class="header-anchor" href="#q-root-后银行-app-打不开怎么办" aria-label="Permalink to &quot;Q: Root 后银行 App 打不开怎么办？&quot;">​</a></h3><ol><li>在 Magisk 设置中开启 <strong>Zygisk</strong></li><li>安装 <strong>Shamiko</strong> 模块隐藏 Root</li><li>在 Magisk 的「配置排除列表」中添加银行应用</li><li>安装 <strong>Play Integrity Fix</strong> 模块</li></ol><h3 id="q-root-后还能-ota-升级吗" tabindex="-1">Q: Root 后还能 OTA 升级吗？ <a class="header-anchor" href="#q-root-后还能-ota-升级吗" aria-label="Permalink to &quot;Q: Root 后还能 OTA 升级吗？&quot;">​</a></h3><p><strong>A/B 分区设备</strong>：</p><ol><li>Magisk → 卸载 → 还原原厂镜像</li><li>下载并安装 OTA（不要重启）</li><li>Magisk → 安装到非活动槽位</li><li>重启</li></ol><p><strong>A-only 设备</strong>：</p><ol><li>下载完整 ROM 包</li><li>提取 boot.img 重新用 Magisk 修补</li><li>刷入修补后的 boot.img</li></ol><h2 id="越狱相关" tabindex="-1">越狱相关 <a class="header-anchor" href="#越狱相关" aria-label="Permalink to &quot;越狱相关&quot;">​</a></h2><h3 id="q-越狱后如何隐藏越狱状态" tabindex="-1">Q: 越狱后如何隐藏越狱状态？ <a class="header-anchor" href="#q-越狱后如何隐藏越狱状态" aria-label="Permalink to &quot;Q: 越狱后如何隐藏越狱状态？&quot;">​</a></h3><ul><li>安装 <strong>Choicy</strong> 插件，针对特定 App 禁用插件注入</li><li>使用 <strong>HideJB</strong> 等屏蔽检测插件</li><li>部分国内银行 App 需要额外方案</li></ul><h3 id="q-不小心升级了系统-还能越狱吗" tabindex="-1">Q: 不小心升级了系统，还能越狱吗？ <a class="header-anchor" href="#q-不小心升级了系统-还能越狱吗" aria-label="Permalink to &quot;Q: 不小心升级了系统，还能越狱吗？&quot;">​</a></h3><p>大概率不能。越狱漏洞通常很快被 Apple 修补。建议：</p><ul><li>关闭自动更新</li><li>安装 <strong>OTADisabler</strong> 等描述文件阻止升级</li><li>如果已经升级，只能等待新的越狱工具发布</li></ul><h2 id="通用" tabindex="-1">通用 <a class="header-anchor" href="#通用" aria-label="Permalink to &quot;通用&quot;">​</a></h2><h3 id="q-哪里可以找到可靠的-rom-资源" tabindex="-1">Q: 哪里可以找到可靠的 ROM/资源？ <a class="header-anchor" href="#q-哪里可以找到可靠的-rom-资源" aria-label="Permalink to &quot;Q: 哪里可以找到可靠的 ROM/资源？&quot;">​</a></h3><ul><li><strong>XDA Developers</strong>：最大的 Android 开发社区</li><li><strong>酷安</strong>：中文搞机社区</li><li><strong>GitHub</strong>：Magisk/LSPosed 模块</li><li><strong>reddit/r/jailbreak</strong>：iOS 越狱讨论</li></ul><div class="tip custom-block"><p class="custom-block-title">提示</p><p>下载 ROM 和工具时请核对文件 MD5/SHA 校验值，确保文件完整未被篡改。</p></div>',29)])])}const p=o(r,[["render",e]]);export{q as __pageData,p as default};
